"use client";

import { useState, useRef, useEffect } from "react";
import { clsx } from "clsx";
import { FileText, Folder, FolderOpen, Link as LinkIcon, CheckCircle, Search, User, ArrowLeft, Clock, Columns, PenTool } from "lucide-react";

// --- データ定義 (HTML準拠) ---
const staffData = { 
  name: '田中 太郎 (第1課)', 
  clients: [
    { id: 'c1', name: '株式会社 鈴木商店', fiscal: 3, groupId: 'yamada', role: 'main' },
    { id: 'c1_sub1', name: '鈴木 太郎 (個人)', fiscal: 3, groupId: 'yamada', role: 'sub' },
    { id: 'c2', name: '合同会社 テック', fiscal: 12 },
    { id: 'c3', name: '山田建設', fiscal: 9 },
    { id: 'c4', name: '佐藤医院', fiscal: 12 },
  ]
};

const periods = { 
  year: ['R7', 'R6', 'R5', 'R4'], 
  month: Array.from({length: 12}, (_, i) => `${12 - i}月`) 
};

// --- メインコンポーネント ---
export default function Home() {
  // State
  const [activeClientIdx, setActiveClientIdx] = useState(0);
  const [mode, setMode] = useState<'year' | 'month'>('year');
  const [activePeriodIdx, setActivePeriodIdx] = useState(1); // 0=PERM, 1~=Periods
  const [viewerOpen, setViewerOpen] = useState(false);
  const [activeDocTitle, setActiveDocTitle] = useState("");
  const [expandedGroup, setExpandedGroup] = useState<string | null>(null);

  // Refs for Scrolling
  const hScrollRef = useRef<HTMLDivElement>(null);
  const vScrollRef = useRef<HTMLDivElement>(null);

  const currentClient = staffData.clients[activeClientIdx];
  const currentPeriodList = ['PERM', ...periods[mode]];
  const currentPeriodLabel = currentPeriodList[activePeriodIdx];
  const isPerm = activePeriodIdx === 0;

  // --- スクロール位置の自動調整ロジック ---
  const scrollToCenter = (axis: 'h' | 'v', index: number) => {
    const ref = axis === 'h' ? hScrollRef.current : vScrollRef.current;
    if (!ref) return;

    if (axis === 'h') {
      // 1アイテム200px計算 (HTMLのCSSに準拠)
      const itemWidth = 200;
      const containerWidth = ref.clientWidth;
      const targetPos = (index * itemWidth) + (itemWidth / 2) - (containerWidth / 2) + (50 * window.innerWidth / 100); 
      // ※↑パディング50vw分を考慮して簡易計算
      
      // 正確にDOM要素から取る
      const items = ref.querySelectorAll('.h-item');
      if (items[index]) {
        const el = items[index] as HTMLElement;
        const offset = el.offsetLeft - (containerWidth / 2) + (el.clientWidth / 2);
        ref.scrollTo({ left: offset, behavior: 'smooth' });
      }
    } else {
      // 縦スクロール
      const items = ref.querySelectorAll('.v-item');
      if (items[index]) {
        const el = items[index] as HTMLElement;
        const offset = el.offsetTop - (ref.clientHeight / 2) + (el.clientHeight / 2);
        ref.scrollTo({ top: offset, behavior: 'smooth' });
      }
    }
  };

  // 初回マウント時と選択変更時にスクロール
  useEffect(() => {
    scrollToCenter('h', activeClientIdx);
  }, [activeClientIdx]);

  useEffect(() => {
    scrollToCenter('v', activePeriodIdx);
  }, [activePeriodIdx]);


  // --- ドキュメントカード生成 ---
  const getDocuments = () => {
    if (isPerm) return ['定款', '履歴事項全部証明書', '株主名簿', '設立届出書', '税務署届出控え', '電子申告IDパス'];
    if (mode === 'year') return ['決算報告書', '総勘定元帳', '法人税申告書', '消費税申告書', '勘定科目内訳書', '概況書'];
    return ['月次試算表', '通帳コピー', '請求書綴り', '給与台帳', '源泉所得税納付書', '議事録'];
  };
  const docList = getDocuments();

  // 進捗率計算（ダミー）
  const progress = isPerm ? 100 : 35;
  const progressColor = isPerm ? '#eab308' : '#3b82f6'; // yellow / blue

  return (
    <div className="text-slate-600 h-screen flex flex-col bg-slate-100 font-sans overflow-hidden">
      
      {/* === 上部ナビゲーション (クライアント選択ドラム) === */}
      <nav className="h-24 bg-slate-900 border-b border-slate-700 relative flex flex-col z-30 shadow-xl flex-shrink-0">
        {/* 背景装飾 */}
        <div className="absolute left-1/2 -translate-x-1/2 bottom-0 w-[200px] h-full bg-white/5 border-x border-white/10 pointer-events-none z-0"></div>
        
        {/* 担当者インジケーター (アニメーション用ダミー) */}
        <div className="absolute top-0 left-0 w-full text-center z-50 pointer-events-none">
           {/* 必要ならここに担当者名を表示 */}
        </div>

        {/* 横スクロールコンテナ */}
        <div 
          ref={hScrollRef}
          className="h-drum-scroller w-full h-full relative z-10 no-scrollbar pt-2"
        >
          {/* 左側の余白 */}
          <div style={{ width: '50vw', flexShrink: 0 }}></div>

          {staffData.clients.map((client, idx) => {
            const isActive = idx === activeClientIdx;
            const isGroup = !!client.groupId;
            const isExpanded = client.groupId === expandedGroup;

            // 表示フィルタ（グループ開閉ロジックは簡易化）
            // HTML版では role='sub' は expandedGroup が一致しないと消えるロジックがありましたが
            // ここでは一旦全表示し、視覚効果のみ適用します
            
            return (
              <div 
                key={client.id}
                onClick={() => setActiveClientIdx(idx)}
                className={clsx(
                  "h-item group-member", 
                  isActive && "active"
                )}
              >
                <div className="flex items-center justify-center gap-1">
                  {client.role === 'main' && (
                     isActive ? <FolderOpen size={16} className="text-blue-400"/> : <Folder size={16} className="opacity-50"/>
                  )}
                  {client.role === 'sub' && <LinkIcon size={14} className="text-blue-400"/>}
                  {client.name}
                </div>
              </div>
            );
          })}

          {/* 右側の余白 */}
          <div style={{ width: '50vw', flexShrink: 0 }}></div>
        </div>

        {/* マスク */}
        <div className="absolute left-0 top-0 h-full w-32 mask-h-left pointer-events-none z-20"></div>
        <div className="absolute right-0 top-0 h-full w-32 mask-h-right pointer-events-none z-20"></div>

        {/* ロゴ */}
        <div className="absolute left-6 top-1/2 -translate-y-1/2 z-50 text-white font-black italic text-xl tracking-tighter cursor-pointer">
          <span className="text-blue-500">Docu</span>Grid
        </div>

        {/* 検索ボタン */}
        <div className="absolute right-4 top-1/2 -translate-y-1/2 z-50">
           <button className="w-10 h-10 rounded-full bg-slate-800 text-slate-400 hover:text-white flex items-center justify-center transition-all shadow-lg border border-white/10">
             <Search size={16} />
           </button>
        </div>
      </nav>

      {/* === メインエリア === */}
      <div className="flex flex-1 overflow-hidden relative">
        
        {/* === 左サイドバー (期間選択ドラム) === */}
        <aside className="w-24 bg-slate-900 h-full relative flex flex-col items-center justify-center shadow-2xl z-20 flex-shrink-0 border-r border-slate-700">
          <div className="absolute top-1/2 -translate-y-1/2 w-full h-20 bg-white/5 border-y border-white/10 pointer-events-none z-0"></div>
          
          {/* モードバッジ */}
          <div 
            onClick={() => setMode(mode === 'year' ? 'month' : 'year')}
            className="absolute top-4 left-1/2 -translate-x-1/2 z-50 cursor-pointer hover:scale-110 transition-transform"
          >
            <span className={clsx("text-[9px] font-black tracking-widest", mode === 'year' ? "text-blue-500" : "text-green-500")}>
              {mode.toUpperCase()}
            </span>
          </div>

          {/* 縦スクロールコンテナ */}
          <div 
            ref={vScrollRef}
            className="v-drum-scroller h-full w-full py-[calc(50vh-80px)] flex flex-col items-center gap-6 relative z-10 no-scrollbar"
          >
             <div style={{ height: '50%', flexShrink: 0 }}></div>
             
             {currentPeriodList.map((p, idx) => {
               const isActive = idx === activePeriodIdx;
               const isP = p === 'PERM';
               return (
                 <div 
                   key={p} 
                   onClick={() => setActivePeriodIdx(idx)}
                   className={clsx("v-item w-full py-4 text-center", isActive && "active")}
                 >
                    {isP ? (
                      <>
                        <div className="text-2xl font-black text-yellow-400">永続</div>
                        <div className="text-[9px] font-bold opacity-60 text-yellow-400">PERM</div>
                      </>
                    ) : (
                      <>
                        <div className={clsx("text-2xl font-black tracking-tighter", 
                          mode === 'month' && parseInt(p) === currentClient.fiscal ? "text-red-500" : "text-white"
                        )}>
                          {p}
                        </div>
                        {mode === 'year' && isActive && <div className="text-[9px] font-bold opacity-60 text-white">YEAR</div>}
                      </>
                    )}
                 </div>
               );
             })}

             <div style={{ height: '50%', flexShrink: 0 }}></div>
          </div>

          {/* マスク */}
          <div className="absolute top-0 left-0 w-full h-24 mask-v-top pointer-events-none z-20"></div>
          <div className="absolute bottom-0 left-0 w-full h-24 mask-v-bottom pointer-events-none z-20"></div>
        </aside>

        {/* === メインコンテンツ (グリッド表示) === */}
        <main className="flex-1 flex flex-col bg-slate-100 relative">
           
           {/* ヘッダー */}
           <header className="bg-white/80 backdrop-blur px-8 py-3 border-b border-slate-200 flex justify-between items-center z-10 h-20">
              <div>
                 <div className="flex items-center gap-2">
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">CLIENT</div>
                    <span className={clsx("text-[9px] font-bold px-1.5 py-0.5 rounded border", 
                      currentClient.fiscal === 3 ? "bg-red-100 text-red-500 border-red-200" : "bg-slate-100 text-slate-500 border-slate-200"
                    )}>
                      {currentClient.fiscal}月決算
                    </span>
                 </div>
                 <div className="text-xl font-bold text-slate-800 leading-tight mt-1 flex items-center">
                    {isPerm ? (
                      <span className="text-yellow-500 mr-2">永続</span> 
                    ) : (
                      <span className={clsx("mr-2", mode === 'year' ? 'text-blue-600' : 'text-green-500')}>
                        {currentPeriodLabel}
                      </span>
                    )}
                    {isPerm ? "永久保存ドキュメント" : (mode === 'year' ? '決算資料' : '月次監査')}
                 </div>
              </div>

              {/* 進捗リング */}
              <div className="flex items-center gap-3">
                 <div className="text-right">
                   <span className="text-2xl font-black" style={{ color: progressColor }}>{progress}%</span>
                 </div>
                 <div className="w-12 h-12 relative flex items-center justify-center">
                    <svg className="transform -rotate-90 w-12 h-12">
                      <circle cx="24" cy="24" r="20" stroke="#e2e8f0" strokeWidth="4" fill="transparent" />
                      <circle 
                        cx="24" cy="24" r="20" 
                        stroke={progressColor} 
                        strokeWidth="4" 
                        fill="transparent" 
                        strokeDasharray="125" 
                        strokeDashoffset={125 - (125 * progress / 100)} 
                        className="transition-all duration-700" 
                      />
                    </svg>
                 </div>
              </div>
           </header>

           {/* カードグリッド */}
           <div className="flex-1 overflow-y-auto p-8">
              <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 animate-fade-in-up">
                 {docList.map((title, i) => {
                   // ダミーロジック: 最初の2つだけ完了していることにする
                   const isFilled = i < 2;
                   
                   if (isFilled) {
                     return (
                       <div 
                         key={title}
                         onClick={() => { setActiveDocTitle(title); setViewerOpen(true); }}
                         className={clsx(
                           "bg-white h-32 rounded-xl border-l-4 shadow-sm p-4 flex flex-col justify-between hover:scale-105 transition-transform cursor-pointer",
                           isPerm ? "border-yellow-400" : "border-indigo-500"
                         )}
                       >
                          <div className="flex justify-between items-start">
                             <FileText className={clsx("text-xl", isPerm ? "text-yellow-500" : "text-indigo-500")} />
                             <CheckCircle className="text-green-500" size={20} />
                          </div>
                          <div className="text-sm font-bold text-slate-700 leading-tight">{title}</div>
                       </div>
                     )
                   } else {
                     return (
                       <div 
                         key={title}
                         className="bg-slate-50 h-32 rounded-xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center text-center p-2 hover:bg-white hover:border-blue-400 transition-colors cursor-pointer group"
                       >
                          <div className="text-slate-300 mb-2 group-hover:text-blue-500 text-2xl">+</div>
                          <div className="text-xs font-bold text-slate-400 group-hover:text-blue-500">{title}</div>
                       </div>
                     )
                   }
                 })}
              </div>
           </div>
        </main>
      </div>

      {/* === ビューワーモーダル (オーバーレイ) === */}
      {viewerOpen && (
        <div className="fixed inset-0 bg-slate-900/95 z-50 flex animate-fade-in-up">
           <div className="flex-1 flex flex-col h-full relative">
              {/* ビューワーヘッダー */}
              <header className="h-14 bg-slate-800 border-b border-slate-700 flex items-center justify-between px-4 flex-shrink-0 z-20">
                 <div className="flex items-center gap-4">
                    <button onClick={() => setViewerOpen(false)} className="text-slate-400 hover:text-white flex items-center gap-2 text-sm font-bold">
                       <ArrowLeft size={16} /> 戻る
                    </button>
                    <div className="h-6 w-px bg-slate-600"></div>
                    <h2 className="text-white font-bold text-sm">{activeDocTitle}</h2>
                    <span className="bg-green-600 text-white text-[10px] font-bold px-2 py-0.5 rounded-full">v6.0 最新版 (申告済)</span>
                 </div>
                 
                 <div className="flex items-center gap-3">
                    <div className="text-[10px] text-slate-400 mr-2 flex items-center gap-1">
                      <PenTool size={10} /> Click to Verify
                    </div>
                    <button className="bg-slate-700 hover:bg-slate-600 text-white w-9 h-9 rounded-lg transition-colors border border-slate-600 flex items-center justify-center">
                       <Clock size={16} />
                    </button>
                    <button className="bg-slate-700 hover:bg-blue-600 text-white w-9 h-9 rounded-lg transition-colors border border-slate-600 flex items-center justify-center">
                       <Columns size={16} />
                    </button>
                    <button className="bg-blue-600 hover:bg-blue-500 text-white px-4 py-1.5 rounded-lg text-xs font-bold shadow-lg flex items-center gap-2">
                       <CheckCircle size={12} /> 完了
                    </button>
                 </div>
              </header>

              {/* ビューワー本体 (Split Viewの片側だけ実装) */}
              <div className="flex-1 flex overflow-hidden relative">
                 <div className="flex-1 bg-slate-100 relative border-r border-slate-300 flex items-center justify-center">
                    <div className="text-center opacity-10">
                       <FileText size={100} className="mx-auto" />
                       <p className="font-black text-4xl mt-4">MAIN DOC</p>
                       <p className="font-bold text-xl mt-2">Version 6.0</p>
                    </div>
                    
                    {/* 上司コメント (ダミー) */}
                    <div className="absolute top-10 left-10 bg-yellow-100 text-yellow-800 p-4 rounded-xl shadow-lg max-w-xs transform rotate-1 border border-yellow-200">
                       <div className="font-bold text-xs mb-1 flex items-center gap-1">
                         <User size={12}/> 上司コメント (v2.0)
                       </div>
                       <p className="text-sm font-bold">交際費の按分が間違っています。前回の議事録を確認して修正してください。</p>
                    </div>
                 </div>
              </div>
           </div>
        </div>
      )}

    </div>
  );
}